// Collect all survey items and tag them for the merge combiner
const responses = $input.all().map(i => i.json);
return [{ json: { _type: 'survey_data', survey_responses: responses } }];

// Both branches have completed. Separate by _type tag.
const items = $input.all().map(i => i.json);

const riskData   = items.find(i => i._type === 'risk_data');
const surveyData = items.find(i => i._type === 'survey_data');

if (!riskData)   throw new Error('Risk data branch did not arrive at merge node.');
if (!surveyData) throw new Error('Survey data branch did not arrive at merge node.');

// Build survey lookup map by member_id
const surveyMap = {};
(surveyData.survey_responses || []).forEach(r => {
  surveyMap[r.member_id] = r;
});

// Attach survey response to each flagged member (HIGH + MEDIUM)
const enriched = riskData.flagged.map(m => ({
  ...m,
  survey_response: surveyMap[m.member_id] || null
}));

// WATCH: members who are LOW risk (attending normally) but rated satisfaction <= 2.
// Different from churn risk — they are still coming, but unhappy.
// Surfaced separately so coaches treat this as proactive, not urgent.
const watch = riskData.all_members
  .filter(m => m.risk_tier === 'LOW')
  .filter(m => {
    const survey = surveyMap[m.member_id];
    return survey && survey.satisfaction_score <= 2;
  })
  .map(m => ({
    ...m,
    risk_tier: 'WATCH',
    survey_response: surveyMap[m.member_id],
    flags: [`Satisfaction rated ${surveyMap[m.member_id].satisfaction_score}/5 — still attending normally`]
  }));

return [{ json: {
  all_members:      riskData.all_members,
  flagged:          enriched,
  watch:            watch,
  survey_responses: surveyData.survey_responses || []
} }];

// Format all flagged + watch members into a single LLM prompt.
// One call replaces N sequential calls — more reliable in n8n and ~80% cheaper.

const data    = $input.first().json;
const flagged = data.flagged || [];
const watch   = data.watch   || [];
const allForLLM = [...flagged, ...watch];

if (allForLLM.length === 0) {
  return [{ json: { ...data, skip_llm: true, llm_prompt: '' } }];
}

const memberSummaries = allForLLM.map(m => {
  const survey = m.survey_response;
  const tier   = m.risk_tier;

  let text = `Member ${m.member_id} [${tier}]: ${m.days_since_last_workout} days since last visit, ${m.avg_sessions_per_week} sessions/week average, ${m.tenure_months} months tenure. Signals: ${(m.flags || []).join(', ')}.`;

  if (survey) {
    text += ` Survey (${survey.submitted_at}): rated ${survey.satisfaction_score}/5.`;
    if (survey.feedback) text += ` Said: "${survey.feedback}".`;
    if (survey.goal_progress) text += ` Goal progress: ${survey.goal_progress}.`;
  } else {
    text += ' No survey response this week.';
  }

  if (tier === 'WATCH') {
    text += ' NOTE: This member is attending regularly — the concern is satisfaction, not attendance. Write a warm, curious note, not an urgent one.';
  }

  return text;
});

const llm_prompt = `You are a fitness studio retention coach. Analyse these members and write a short, warm, actionable coaching note for each one (2-3 sentences max per member). Be specific to their data.\n\n${memberSummaries.join('\n\n')}`;

return [{ json: { ...data, skip_llm: false, llm_prompt } }];

// Parse batched LLM response and build the full HTML email.
const llmResponse = $input.first().json;
const memberData = $('Prepare LLM Prompt').first().json;

const allMembers      = memberData.all_members     || [];
const flagged         = memberData.flagged          || [];
const watchMembers    = memberData.watch            || [];
const surveyResponses = memberData.survey_responses || [];

// Extract briefings from native Claude node or OpenAI HTTP node
const raw = (typeof llmResponse.output === 'string' ? llmResponse.output : null)
         || llmResponse.output?.[0]?.content?.[0]?.text
         || llmResponse.choices?.[0]?.message?.content
         || null;

let briefings = [];
if (raw && typeof raw === 'object') {
  briefings = raw.briefings || [];
} else if (raw && typeof raw === 'string') {
  try {
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    briefings = JSON.parse(cleaned).briefings || [];
  } catch(e) {}
}

const briefingMap = {};
for (const b of briefings) {
  briefingMap[b.member_id] = b.text;
}

const reportDate    = new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
const totalMembers  = allMembers.length;
const atRiskCount   = flagged.length;
const highRisk      = flagged.filter(m => m.risk_tier === 'HIGH').length;
const totalLtvAtRisk = flagged.reduce((sum, m) => sum + (m.ltv_at_risk || 0), 0);

// ── Section 1: Risk member cards (HIGH + MEDIUM) ───────────────────────────
const riskCards = flagged.map(m => {
  const briefingText = briefingMap[m.member_id] || 'No coaching note generated.';
  const tierColor    = m.risk_tier === 'HIGH' ? '#e53e3e' : '#d69e2e';
  const survey       = m.survey_response;
  const surveyHtml   = survey
    ? `<p style="margin:4px 0;color:#718096;font-size:13px;">&#128172; "${survey.feedback}" — ${survey.satisfaction_score}/5 satisfaction</p>`
    : `<p style="margin:4px 0;color:#a0aec0;font-size:13px;">No survey response this week</p>`;
  return `
    <div style="border:1px solid #e2e8f0;border-radius:8px;padding:16px;margin-bottom:12px;background:#fff;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
        <strong style="font-size:16px;">${m.name || m.member_id}</strong>
        <span style="background:${tierColor};color:#fff;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:bold;">${m.risk_tier}</span>
      </div>
      <p style="margin:4px 0;color:#4a5568;font-size:13px;">&#128197; ${m.days_since_last_workout} days since last visit &nbsp;|&nbsp; &#128202; ${m.avg_sessions_per_week} sessions/week &nbsp;|&nbsp; &#128197; ${m.tenure_months} months tenure</p>
      ${surveyHtml}
      <div style="background:#f7fafc;border-left:3px solid #667eea;padding:10px;margin-top:10px;border-radius:4px;">
        <p style="margin:0;font-size:13px;color:#4a5568;"><strong>Coaching note:</strong> ${briefingText}</p>
      </div>
    </div>`;
}).join('');

// ── Section 2: Survey snapshot ─────────────────────────────────────────────
const avgSatisfaction = surveyResponses.length
  ? (surveyResponses.reduce((s, r) => s + (r.satisfaction_score || 0), 0) / surveyResponses.length).toFixed(1)
  : 'N/A';
const avgNps = surveyResponses.length
  ? (surveyResponses.reduce((s, r) => s + (r.nps_score || 0), 0) / surveyResponses.length).toFixed(1)
  : 'N/A';

// ── Section 3: WATCH — low satisfaction, still attending ──────────────────
const watchCards = watchMembers.map(m => {
  const survey       = m.survey_response;
  const briefingText = briefingMap[m.member_id] || '';
  return `
    <div style="border:1px solid #d6bcfa;border-radius:8px;padding:16px;margin-bottom:12px;background:#faf5ff;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
        <strong style="font-size:16px;">${m.name || m.member_id}</strong>
        <span style="background:#6c3483;color:#fff;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:bold;">WATCH</span>
      </div>
      <p style="margin:4px 0;color:#4a5568;font-size:13px;">Attending normally — ${m.avg_sessions_per_week} sessions/week &nbsp;|&nbsp; last visit ${m.days_since_last_workout} days ago</p>
      <p style="margin:4px 0;color:#6c3483;font-size:13px;font-weight:bold;">Satisfaction: ${survey.satisfaction_score}/5${survey.nps_score ? ' &nbsp;|&nbsp; NPS: ' + survey.nps_score + '/10' : ''}</p>
      ${survey.feedback ? `<p style="margin:4px 0;color:#718096;font-size:13px;">&#128172; "${survey.feedback}"</p>` : ''}
      ${briefingText ? `<div style="background:#f3e8ff;border-left:3px solid #6c3483;padding:10px;margin-top:10px;border-radius:4px;"><p style="margin:0;font-size:13px;color:#4a5568;"><strong>Coaching note:</strong> ${briefingText}</p></div>` : ''}
    </div>`;
}).join('');

const watchSection = watchMembers.length > 0 ? `
  <div style="background:#fff;border-radius:12px;padding:20px;margin-bottom:24px;border:1px solid #d6bcfa;">
    <h2 style="margin:0 0 8px;font-size:18px;color:#6c3483;">&#128101; Satisfaction Alerts</h2>
    <p style="margin:0 0 16px;color:#718096;font-size:13px;">These members are <strong>still attending</strong> but rated satisfaction 2/5 or lower. No urgency — a warm personal check-in this week can prevent this becoming an attendance problem.</p>
    ${watchCards}
  </div>` : '';

// ── Assemble full email ────────────────────────────────────────────────────
const email_html = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f7fafc;margin:0;padding:20px;">
<div style="max-width:620px;margin:0 auto;">

  <div style="background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;padding:28px;border-radius:12px;margin-bottom:24px;text-align:center;">
    <h1 style="margin:0 0 6px;font-size:24px;">Spottr Weekly Report</h1>
    <p style="margin:0;opacity:0.85;font-size:14px;">${reportDate}</p>
  </div>

  <div style="display:flex;gap:12px;margin-bottom:24px;">
    <div style="flex:1;background:#fff;border-radius:8px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:28px;font-weight:bold;color:#667eea;">${totalMembers}</div>
      <div style="font-size:12px;color:#718096;">Total Members</div>
    </div>
    <div style="flex:1;background:#fff;border-radius:8px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:28px;font-weight:bold;color:#e53e3e;">${atRiskCount}</div>
      <div style="font-size:12px;color:#718096;">At-Risk</div>
    </div>
    <div style="flex:1;background:#fff;border-radius:8px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:28px;font-weight:bold;color:#d69e2e;">${highRisk}</div>
      <div style="font-size:12px;color:#718096;">High Risk</div>
    </div>
    <div style="flex:1;background:#fff;border-radius:8px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:28px;font-weight:bold;color:#6c3483;">${watchMembers.length}</div>
      <div style="font-size:12px;color:#718096;">Watch</div>
    </div>
  </div>

  <div style="background:#fff;border-radius:12px;padding:20px;margin-bottom:24px;border:1px solid #e2e8f0;">
    <h2 style="margin:0 0 16px;font-size:18px;color:#2d3748;">&#128680; Members Needing Attention</h2>
    ${riskCards || '<p style="color:#718096;">No at-risk members this week.</p>'}
  </div>

  ${watchSection}

  <div style="background:#fff;border-radius:12px;padding:20px;margin-bottom:24px;border:1px solid #e2e8f0;">
    <h2 style="margin:0 0 16px;font-size:18px;color:#2d3748;">&#128203; Survey Snapshot (Last 7 Days)</h2>
    <p style="margin:4px 0;color:#4a5568;">Responses received: <strong>${surveyResponses.length}</strong></p>
    <p style="margin:4px 0;color:#4a5568;">Avg satisfaction: <strong>${avgSatisfaction}/5</strong></p>
    <p style="margin:4px 0;color:#4a5568;">Avg NPS: <strong>${avgNps}/10</strong></p>
  </div>

  <p style="text-align:center;color:#a0aec0;font-size:12px;">Generated by Spottr &nbsp;&#183;&nbsp; ${reportDate}</p>
</div>
</body>
</html>`;

return [{ json: { email_html } }];

const members = $input.all().map(item => item.json);

const DAYS_HIGH_RISK = 21;
const LTV_PER_MONTH = 125;

const scored = members.map(m => {
  let risk_score = 0;
  let risk_tier = 'LOW';
  const flags = [];

  if (m.days_since_last_workout >= DAYS_HIGH_RISK) {
    risk_score += 3;
    flags.push(`${m.days_since_last_workout} days since last visit`);
  } else if (m.days_since_last_workout >= 14) {
    risk_score += 2;
    flags.push(`${m.days_since_last_workout} days since last visit`);
  } else if (m.days_since_last_workout >= 7) {
    risk_score += 1;
  }

  if (m.avg_sessions_per_week < 1.0 && m.tenure_months > 2) {
    risk_score += 2;
    flags.push('visit frequency below 1/week for established member');
  } else if (m.avg_sessions_per_week < 1.5 && m.tenure_months > 2) {
    risk_score += 1;
    flags.push('visit frequency declining');
  }

  if (m.tenure_months <= 3) {
    risk_score += 1;
    flags.push('new member — high churn risk window');
  }

  if (risk_score >= 4) risk_tier = 'HIGH';
  else if (risk_score >= 2) risk_tier = 'MEDIUM';
  else risk_tier = 'LOW';

  const ltv_at_risk = Math.round(LTV_PER_MONTH * Math.max(1, 12 - m.tenure_months));

  return { ...m, risk_score, risk_tier, flags, ltv_at_risk };
});

scored.sort((a, b) => b.risk_score - a.risk_score);

return [{ json: { _type: 'risk_data', all_members: scored, flagged: scored.filter(m => m.risk_tier !== 'LOW') } }];

return [
