  { json: { member_id: 'M006', name: 'Chris N.', phone: '+49 163 7712 9904', tenure_months: 18, days_since_last_workout: 5, avg_sessions_per_week: 2.8, plan: 'Premium', join_date: '2023-09-01' } },
  { json: { member_id: 'M007', name: 'Anna P.', phone: '+49 157 4401 5537', tenure_months: 3, days_since_last_workout: 15, avg_sessions_per_week: 1.0, plan: 'Basic', join_date: '2025-12-20' } },
  { json: { member_id: 'M008', name: 'David L.', phone: '+49 174 6623 8819', tenure_months: 11, days_since_last_workout: 22, avg_sessions_per_week: 0.7, plan: 'Premium', join_date: '2024-04-08' } }
];

