  { json: { response_id: 'R001', member_id: 'M001', submitted_at: '2026-03-24T09:15:00', satisfaction_score: 3, nps_score: 5, feedback: 'Been busy with work, hoping to get back on track soon.', goal_progress: 'falling_behind' } },
