  { json: { response_id: 'R004', member_id: 'M007', submitted_at: '2026-03-26T08:45:00', satisfaction_score: 4, nps_score: 7, feedback: 'Still finding my rhythm as a new member.', goal_progress: 'getting_started' } },
  { json: { response_id: 'R005', member_id: 'M008', submitted_at: '2026-03-23T14:20:00', satisfaction_score: 2, nps_score: 4, feedback: 'Schedule conflicts making it hard to come in regularly.', goal_progress: 'falling_behind' } }
];
